import {
  Component,
  Element,
  Prop,
  Host,
  h,
  Method,
  Watch
} from '@stencil/core';
import { generateUniqueString } from '@src/utils/kds-utils/generateUniqueString';
import { Fragment } from '@src/utils/kds-utils/fragment';
import { isTruthyOrZero } from '@src/utils/kds-utils/objectUtils';

/**
 * A ButtonGroup member to be provided as a child to a kds-buttongroup component.
 */
@Component({
  tag: 'kds-buttongroup-member',
  shadow: false
})
export class KdsButtonGroupMember {
  @Element() hostEl: HTMLKdsButtongroupMemberElement;
  /** Sets member to disabled state if true */
  @Prop() readonly disabled?: boolean = false;
  /** Semantically applies member's aria label with given value. */
  @Prop() readonly readerLabel!: string;
  /** Sets underlying checkbox or radio button to be selected by default. */
  @Prop({ mutable: true }) defaultSelected?: boolean;
  /** Determines the icon to use. */
  @Prop() readonly icon?: string;
  /** Text to render inside of the member. */
  @Prop() readonly textLabel?: string;
  /** Sets the value of a badge to be rendered on provided icon. */
  @Prop() readonly badgeValue?: number;
  /** Sets the placement of the icon in a member to the right or left of text. */
  @Prop() readonly iconPlacement?: 'left' | 'right' = 'left';

  @Prop() readonly tooltip?: boolean = false;
  @Prop() readonly tooltipSide: 'top' | 'bottom' | 'left' | 'right' = 'bottom';
  @Prop() readonly tooltipAlign: 'center' | 'left' | 'right' = 'center';
  @Prop() readonly tooltipType: 'label' | 'description' = 'description';

  @Prop() readonly tooltipText?: string = this.readerLabel;

  private uniqueId: string = generateUniqueString();

  private buttonGroup: HTMLKdsButtongroupElement;

  private inputElement: HTMLInputElement;

  componentWillLoad() {
    this.buttonGroup = this.hostEl.parentElement as HTMLKdsButtongroupElement;

    this.validateReaderLabel(this.readerLabel);
  }

  @Watch('readerLabel')
  validateReaderLabel(readerLabel: string) {
    if (readerLabel && readerLabel.length > 0) {
      return;
    } else {
      console.error(
        `🚨 Accessibility No-No: You must set a reader-label on kds-buttongroup-member for proper screen reader dictation.`
      );
    }
  }

  renderIcon(iconOnly: boolean) {
    const Icon = this.icon;

    if (isTruthyOrZero(this.badgeValue)) {
      return (
        <kds-badge
          class={{
            'kds-ButtonGroup-member-icon': true,
            'kds-ButtonGroup-member-badge': true
          }}
          count={this.badgeValue}
          palette={this.buttonGroup.palette}
          kind='dominant'
        >
          <Icon size='m' />
        </kds-badge>
      );
    } else {
      return (
        <Icon
          size='m'
          class={{
            'kds-ButtonGroup-member-icon': true,
            'kds-ButtonGroup-member-icon--onlyChild': iconOnly
          }}
          palette={this.buttonGroup.palette}
          kind={this.buttonGroup.kind}
          variant={this.buttonGroup.variant}
          inverse={this.buttonGroup.variant === 'fill'}
        />
      );
    }
  }

  renderText(iconOnly: boolean) {
    return iconOnly ? (
      <span
        class='kds-ButtonGroup-member-text'
        aria-hidden='true'
        title={this.readerLabel || ''}
      />
    ) : (
      <span class='kds-ButtonGroup-member-text'>{this.textLabel}</span>
    );
  }

  buildLabel() {
    let ariaLabel =
      this.readerLabel || this.textLabel || this.icon.replace('kds-icon-', '');
    ariaLabel = isTruthyOrZero(this.badgeValue)
      ? `${ariaLabel}: ${this.badgeValue}`
      : ariaLabel;
    return ariaLabel;
  }

  /** Selects member when called. Only valid for `checkbox` and `radio` group types. */
  @Method()
  async selectMember() {
    if (this.inputElement) {
      this.inputElement.checked = true;
    } else {
      this.defaultSelected = true;
    }
  }

  render() {
    let iconOnly: boolean = this.icon && !this.textLabel;
    const ariaLabel = this.buildLabel();
    const isVariantFillAndNotTypeOfButton =
      this.buttonGroup.variant === 'fill' &&
      this.buttonGroup.groupType !== 'button';
    const calculatedVariant = isVariantFillAndNotTypeOfButton
      ? 'border'
      : this.buttonGroup.variant;
    const classes = {
      [`palette-${this.buttonGroup.palette}`]: true,
      [`kind-${this.buttonGroup.kind}`]: true,
      [`variant-${calculatedVariant}`]: true,
      'as-inverse': this.buttonGroup.inverse,
      'is-disabled': this.disabled,
      interactive: true
    };

    const TypeJSX = () => (
      <input
        type={this.buttonGroup.groupType}
        id={`kds-ButtonGroup-input-${this.uniqueId}`}
        name={
          this.buttonGroup.groupType === 'radio' && this.buttonGroup.groupName
        }
        aria-label={ariaLabel}
        checked={
          this.inputElement ? this.inputElement.checked : this.defaultSelected
        }
        ref={(el) => (this.inputElement = el instanceof HTMLInputElement && el)}
        class={{
          'kds-ButtonGroup-input': true
        }}
      ></input>
    );

    const LabelJSX = () => (
      <label
        htmlFor={`kds-ButtonGroup-input-${this.uniqueId}`}
        class={{
          'kds-ButtonGroup-member': true,
          'kds-ButtonGroup-member--hasIconOnly': iconOnly,
          ...classes
        }}
        aria-hidden='true'
        onClick={(event) => event.stopPropagation()}
      >
        {this.icon &&
          this.iconPlacement === 'left' &&
          this.renderIcon(iconOnly)}
        {this.renderText(iconOnly)}
        <slot />
        {this.icon &&
          this.iconPlacement === 'right' &&
          this.renderIcon(iconOnly)}
      </label>
    );

    return (
      <Host
        class='kds-ButtonGroup-member-wrapper'
        style={this.disabled && { 'pointer-events': 'none' }}
      >
        <Fragment>
          <TypeJSX />
          {this.tooltip ? (
            <kds-tooltippable
              side={this.tooltipSide}
              align={this.tooltipAlign}
              tooltipText={this.tooltipText}
              tooltipType={this.tooltipType}
            >
              <LabelJSX />
              <slot name='tooltipText' />
            </kds-tooltippable>
          ) : (
            <LabelJSX />
          )}
        </Fragment>
      </Host>
    );
  }
}
